  if (!periodo) return 11;
  const mesNum = parseInt(periodo.toString().slice(-2));
  return mesNum - 1;
}

const mesLimiteIndex = getMesIndex(periodoLimite);

const linhasPorSeq = {};
items.forEach(item => {
  linhasPorSeq[item.json.dre_linha_seq] = { ...item.json };
});

function corrigirFormula(formula) {
  if (!formula || typeof formula !== 'string') return formula;
  return formula.replace(/L#(\d+)/g, '#L$1').trim();
}

function expandirSomaLinha(formula) {
  const regex = /SOMA_LINHA\(#L(\d+):#L(\d+)\)/g;
  return formula.replace(regex, (match, inicio, fim) => {
    const linhas = [];
    for (let i = parseInt(inicio); i <= parseInt(fim); i++) {
      linhas.push(`#L${i}`);
    }
    return linhas.join('+');
  });
}

function expandirPerc(formula) {
  const regex = /PERC\(([^)]+)\)/g;
  return formula.replace(regex, (match, expressao) => `((${expressao})*100)`);
}

function getValorLinha(numLinha, mes) {
  const linha = linhasPorSeq[numLinha];
  if (!linha) return 0;
  if (linha.valoresCalculados && linha.valoresCalculados[mes] !== undefined) {
    return linha.valoresCalculados[mes] || 0;
  }
  const valor = linha[mes];
  return valor !== null && valor !== undefined ? valor : 0;
}

function calcularFormula(formula, mes) {
  let expressao = formula.replace(/#L(\d+)/g, (match, numLinha) => {
    return getValorLinha(parseInt(numLinha), mes);
  });
  try {
    const resultado = eval(expressao);
    return isFinite(resultado) ? resultado : 0;
  } catch (error) {
    return 0;
  }
}

Object.values(linhasPorSeq).forEach(linha => {
  if (linha.tipo_linha !== 'FORMULA') return;

  let formula = linha.dre_linha_valor;

  if (!formula ||
      formula.includes('APONTA PARA CONTA') ||
      formula.includes('QUE NAO TEM') ||
      formula.includes('PLANO DE CONTAS')) {
    return;
  }

  formula = corrigirFormula(formula);

  const isConstante = /^-?\d+(\.\d+)?$/.test(formula);

  if (isConstante) {
    const valorConstante = parseFloat(formula);
    const valores = {};
    meses.forEach((mes, index) => {
      valores[mes] = index <= mesLimiteIndex ? valorConstante : 0;
    });
    valores.conta_acumulado = valorConstante;
    linhasPorSeq[linha.dre_linha_seq] = {
      ...linha,
      ...valores,
      valoresCalculados: valores,
      formula_original: linha.dre_linha_valor,
      formula_processada: formula
    };
    return;
  }

  formula = expandirSomaLinha(formula);
  formula = expandirPerc(formula);

  const valores = {};
  let somaAcumulado = 0;

  meses.forEach((mes, index) => {
    if (index <= mesLimiteIndex) {
      const valor = calcularFormula(formula, mes);
      valores[mes] = valor;
      somaAcumulado += valor;
    } else {
      valores[mes] = 0;
    }
  });

  valores.conta_acumulado = somaAcumulado;

  linhasPorSeq[linha.dre_linha_seq] = {
    ...linha,
    ...valores,
    valoresCalculados: valores,
    formula_original: linha.dre_linha_valor,
    formula_processada: formula
  };
});

const todasLinhas = Object.values(linhasPorSeq);
todasLinhas.sort((a, b) => a.dre_linha_seq - b.dre_linha_seq);

return todasLinhas.map(linha => ({ json: linha }));

