let processados = 0;
let ignorados = 0;

// Processa FORMULA
Object.values(linhasPorSeq).forEach(linha => {
  if (linha.tipo_linha !== 'FORMULA') {
    return;
  }

  let formula = linha.dre_linha_valor;

  // Ignora fórmulas inválidas
  if (!formula || 
      formula.includes('APONTA PARA CONTA') || 
      formula.includes('QUE NAO TEM') ||
      formula.includes('PLANO DE CONTAS')) {
    console.log(`⚠️  Ignorado L${linha.dre_linha_seq} - ${formula}`);
