// Processa FORMULA
Object.values(linhasPorSeq).forEach(linha => {
  if (linha.tipo_linha !== 'FORMULA') {
    return;
  }

  let formula = linha.dre_linha_valor;

  // Ignora fórmulas inválidas
  if (!formula || 
      formula.includes('APONTA PARA CONTA') || 
      formula.includes('QUE NAO TEM') ||
      formula.includes('PLANO DE CONTAS')) {
    console.log(`⚠️  Ignorado L${linha.dre_linha_seq} - ${formula}`);
    ignorados++;
    return;
  }

  // Processa
  formula = corrigirFormula(formula);

  // Verifica se é constante numérica
  const isConstante = /^-?\d+(\.\d+)?$/.test(formula);

  if (isConstante) {
    const valorConstante = parseFloat(formula);
    const valores = {};

    meses.forEach((mes, index) => {
      valores[mes] = index <= mesLimiteIndex ? valorConstante : 0;
    });
    valores.conta_acumulado = valorConstante;

    linhasPorSeq[linha.dre_linha_seq] = {
      ...linha,
      ...valores,
      valoresCalculados: valores,
      formula_original: linha.dre_linha_valor,
      formula_processada: formula
    };

    processados++;
    console.log(`✅ CONSTANTE L${linha.dre_linha_seq} = ${valorConstante}`);
    return;
  }

  // Expande funções
  formula = expandirSomaLinha(formula);
  formula = expandirPerc(formula);

  // Calcula mês a mês
  const valores = {};
  let somaAcumulado = 0;

  meses.forEach((mes, index) => {
    if (index <= mesLimiteIndex) {
      const valor = calcularFormula(formula, mes);
      valores[mes] = valor;
      somaAcumulado += valor;
    } else {
      valores[mes] = 0;
    }
  });

  valores.conta_acumulado = somaAcumulado;

  linhasPorSeq[linha.dre_linha_seq] = {
    ...linha,
    ...valores,
    valoresCalculados: valores,
    formula_original: linha.dre_linha_valor,
    formula_processada: formula
  };

  processados++;
  console.log(`✅ FORMULA L${linha.dre_linha_seq} - ${linha.dre_linha_descri}`);
});

// Retorna TODAS
const todasLinhas = Object.values(linhasPorSeq);
todasLinhas.sort((a, b) => a.dre_linha_seq - b.dre_linha_seq);

console.log(`📊 Fórmulas processadas: ${processados}`);
console.log(`⚠️  Fórmulas ignoradas: ${ignorados}`);
console.log(`📦 Total linhas: ${todasLinhas.length}\n`);

return todasLinhas.map(linha => ({ json: linha }));

// ===== NODE 3: ACUMULADOS (ACUM VLR ANT) =====
// Processa linhas do tipo ACUM VLR ANT
// Input: Todas as linhas (com BASE + FORMULAS já calculadas)
// Output: Todas as linhas (com ACUMULADOS calculados)

const items = $input.all();
const meses = [
  'conta_janeiro', 'conta_fevereiro', 'conta_marco', 'conta_abril',
  'conta_maio', 'conta_junho', 'conta_julho', 'conta_agosto',
  'conta_setembro', 'conta_outubro', 'conta_novembro', 'conta_dezembro'
];

// Captura período limite
let periodoLimite = null;
items.forEach(item => {
  if (!periodoLimite && item.json.crg_periodo) {
    periodoLimite = item.json.crg_periodo;
  }
});

function getMesIndex(periodo) {
  if (!periodo) return 11;
  const mesNum = parseInt(periodo.toString().slice(-2));
  return mesNum - 1;
}

const mesLimiteIndex = getMesIndex(periodoLimite);

console.log(`\n📈 NODE 3: ACUMULADOS - Período ${periodoLimite}`);

// Cria mapa
const linhasPorSeq = {};
items.forEach(item => {
  linhasPorSeq[item.json.dre_linha_seq] = { ...item.json };
});

function getValorLinha(numLinha, mes) {
  const linha = linhasPorSeq[numLinha];
  if (!linha) {
    console.warn(`⚠️  Linha #L${numLinha} não encontrada`);
    return 0;
  }

  if (linha.valoresCalculados && linha.valoresCalculados[mes] !== undefined) {
    return linha.valoresCalculados[mes] || 0;
  }

  const valor = linha[mes];
  return valor !== null && valor !== undefined ? valor : 0;
}

function calcularAcumuladoValorAnterior(refLinha, mesLimiteIndex) {
  const match = refLinha.match(/#L(\d+)/);
  if (!match) {
    console.warn(`⚠️  Referência inválida: ${refLinha}`);
    return null;
  }

  const numLinhaRef = parseInt(match[1]);
  const linhaReferenciada = linhasPorSeq[numLinhaRef];

  if (!linhaReferenciada) {
    console.warn(`⚠️  Linha #L${numLinhaRef} não encontrada`);
    return null;
  }

  const valores = {};
  let acumulado = 0;

  meses.forEach((mes, index) => {
    if (index <= mesLimiteIndex) {
      const valorMes = getValorLinha(numLinhaRef, mes);
      acumulado += valorMes;
      valores[mes] = acumulado;
    } else {
      valores[mes] = 0;
    }
  });

  valores.conta_acumulado = valores[meses[mesLimiteIndex]];

  return valores;
}

let processados = 0;

// Processa ACUM VLR ANT
Object.values(linhasPorSeq).forEach(linha => {
  if (linha.tipo_linha !== 'ACUM VLR ANT') {
    return;
  }

  const referencia = linha.dre_linha_valor;

  if (!referencia) {
    console.warn(`⚠️  L${linha.dre_linha_seq} sem referência`);
    return;
  }

  const valores = calcularAcumuladoValorAnterior(referencia, mesLimiteIndex);

  if (valores) {
    linhasPorSeq[linha.dre_linha_seq] = {
      ...linha,
      ...valores,
      valoresCalculados: valores,
      referencia_original: referencia
    };

    processados++;
    console.log(`✅ ACUM L${linha.dre_linha_seq} - ${linha.dre_linha_descri} (ref: ${referencia})`);
  }
});

// Retorna TODAS
const todasLinhas = Object.values(linhasPorSeq);
todasLinhas.sort((a, b) => a.dre_linha_seq - b.dre_linha_seq);

console.log(`📊 Acumulados processados: ${processados}`);
console.log(`📦 Total linhas: ${todasLinhas.length}\n`);

return todasLinhas.map(linha => ({ json: linha }));

// ===== NODE 4: PERCENTUAIS =====
// Calcula percentuais de TODAS as linhas com base em perc_ref
// Input: Todas as linhas (completas)
// Output: Todas as linhas com conta_perc calculado

const items = $input.all();

console.log(`\n📊 NODE 4: PERCENTUAIS`);

// Cria mapa
const linhasPorSeq = {};
items.forEach(item => {
  linhasPorSeq[item.json.dre_linha_seq] = { ...item.json };
});

let processados = 0;
let semPerc = 0;
let erros = 0;

// Processa TODOS os percentuais
Object.values(linhasPorSeq).forEach(linha => {
  const percRef = linha.perc_ref;

  // Sem perc_ref = null
  if (!percRef || percRef === '') {
    linha.conta_perc = null;
    semPerc++;
    return;
  }

  // #L% = linha base (100%)
  if (percRef === '#L%') {
    linha.conta_perc = 1;
    processados++;
    console.log(`✅ BASE L${linha.dre_linha_seq} - ${linha.dre_linha_descri} = 100%`);
    return;
  }

  // #L%% = não calcula
  if (percRef === '#L%%') {
    linha.conta_perc = null;
    semPerc++;
    return;
  }

  // #L## = referência a outra linha
  const match = percRef.match(/#L(\d+)/);
  if (match) {
    const numLinhaRef = parseInt(match[1]);
    const linhaReferenciada = linhasPorSeq[numLinhaRef];

    if (!linhaReferenciada) {
      console.warn(`⚠️  L${linha.dre_linha_seq} - Ref #L${numLinhaRef} não encontrada`);
      linha.conta_perc = null;
      erros++;
      return;
    }

    const valorAtual = linha.conta_acumulado || 0;
    const valorReferencia = linhaReferenciada.conta_acumulado || 0;

    if (valorReferencia === 0) {
      linha.conta_perc = 0;
      console.log(`⚠️  L${linha.dre_linha_seq} - Divisão por zero (ref: #L${numLinhaRef})`);
    } else {
      linha.conta_perc = valorAtual / valorReferencia;
      processados++;
      const percFormatado = (linha.conta_perc * 100).toFixed(2);
      console.log(`✅ PERC L${linha.dre_linha_seq} = ${percFormatado}% (ref: #L${numLinhaRef})`);
    }
    return;
  }

  // Formato inválido
  console.warn(`⚠️  L${linha.dre_linha_seq} - perc_ref inválido: ${percRef}`);
  linha.conta_perc = null;
  erros++;
});

// Retorna TODAS
const todasLinhas = Object.values(linhasPorSeq);
todasLinhas.sort((a, b) => a.dre_linha_seq - b.dre_linha_seq);

console.log(`📊 Percentuais calculados: ${processados}`);
console.log(`⚠️  Sem percentual: ${semPerc}`);
console.log(`❌ Erros: ${erros}`);
console.log(`📦 Total linhas: ${todasLinhas.length}\n`);

return todasLinhas.map(linha => ({ json: linha }));
